INSERT INTO meal_plans (user_id, name, description, duration_days, is_template) VALUES (NULL, '60 天 Lean Bulk 餐單', '為期 60 天的 Lean Bulk 飲食範本，包含每日四餐與補充建議。', 60, TRUE);
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 1, 1, '星期一', '全麥多士2片 + 炒蛋 (2全蛋+2蛋白) + 蘑菇番茄 + 1/4個牛油果', '味噌烤三文魚 130g + 藜麥糙米飯 200g + 四季豆', '全麥方包 1片 + 吞拿魚(水浸) 半罐 + 低脂沙律醬', '雞胸肉法吉塔 (Fajitas: 雞胸 150g + 甜椒 + 洋蔥 + 墨西哥捲餅皮 2片)', '【訓練日】黑豆漿 1 杯 + 奇異果 1 個 (休息日替換)', '週末可先煮好白飯與藜麥分裝冷凍；雞腿肉先用無糖醬油醃製。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 2, 1, '星期二', '希臘乳酪 200g + 燕麥脆片(Granola) 50g + 蜂蜜1湯匙 + 香蕉1隻', '番茄肉醬意粉 (瘦豬肉碎 150g + 全麥意粉 100g乾重 + 洋蔥番茄熬汁)', '香蕉 1隻 + 希臘乳酪 100g', '清蒸石斑/鱸魚 200g (薑蔥豉油少許) + 白飯 200g + 炒生菜', '【訓練日】乳清蛋白粉 1 勺 + 穀物片小半碗', '按照當日食譜烹調，注意少油少糖。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 3, 1, '星期三', '高蛋白鬆餅 (燕麥粉 + 乳清蛋白1勺 + 雞蛋) + 無糖糖漿 + 奇異果', '日式咖哩雞胸肉 150g (無糖咖哩粉+少量蘋果泥) + 薯仔/紅蘿蔔 + 白飯 200g', '高蛋白能量棒 (Protein Bar) 1條', '黑椒蘑菇烤豬鞍片 (150g) + 薯蓉 (薯仔200g+低脂奶打成) + 蘆筍', '【休息日】乳清蛋白粉 1 勺 (不需高碳水)', '按照當日食譜烹調，注意少油少糖。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 4, 1, '星期四', '蕎麥麵 (冷) + 水煮蛋2隻 + 海帶芽 + 芝麻醬少許', '蒜香牛油煎白身魚 (龍脷/鯛魚 200g) + 烤番薯 250g + 翠玉瓜', '無糖豆漿 1盒 + 梳打餅 1小包', '香煎牛板腱 (Flat Iron) 150g + 烤南瓜 250g + 蒜蓉炒芥蘭', '【訓練日】乳清蛋白粉 1 勺 + 蜂蜜燕麥棒 1 條', '按照當日食譜烹調，注意少油少糖。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 5, 1, '星期五', '牛肉碎粥 (白飯熬製 + 瘦牛肉碎 100g) + 蔥花 + 薑絲', '韓式辣醬炒豬梅肉(去肥) 150g + 紫菜包飯 (飯200g) + 菠菜', '米餅 (Rice Cakes) 3塊 + 抹低脂忌廉芝士 + 火雞胸肉片 3片', '滑蛋蝦仁 (大蝦 150g + 2蛋) + 白飯 200g + 燙小白菜', '【訓練日】無糖高鈣奶 250ml + 蘋果 1 個 (休息日替換)', '薯仔和南瓜切塊蒸熟，放保鮮盒；大蝦可買急凍剝殼蝦仁退冰。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 6, 1, '星期六', '花生醬香蕉三文治 (全麥包2片 + 花生醬1.5湯匙 + 香蕉1隻) + 脫脂奶一條', '照燒去皮雞腿肉 150g + 白飯 200g + 西蘭花 1.5碗 (備餐神器)', '蘋果 1個 + 杏仁/核桃 20g', '泰式打拋豬肉 (瘦豬絞肉 150g + 九層塔 + 番茄) + 糙米飯 200g', '【休息日】茅屋芝士 (Cottage Cheese) 100g (不需高碳水)', '按照當日食譜烹調，注意少油少糖。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 7, 1, '星期日', '隔夜燕麥 (燕麥80g + 脫脂奶200ml + 奇亞籽1茶匙 + 乳清半勺 + 藍莓)', '黑椒洋蔥炒瘦牛柳絲 150g + 烏冬 1.5個 + 菜心 1.5碗', '水煮蛋 2隻 + 地瓜 100g', '蒜香辣椒大蜆炒意粉 (大蜆/青口 200g + 全麥意粉 100g) + 雜菜沙律', '【休息日】乳清蛋白粉 1 勺 (不需高碳水)', '豬鞍/豬梅肉用蒜茸和少許生抽醃製；燕麥可前一晚做好放雪櫃。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 8, 2, '星期一', '希臘乳酪 200g + 燕麥脆片(Granola) 50g + 蜂蜜1湯匙 + 香蕉1隻', '日式咖哩雞胸肉 150g (無糖咖哩粉+少量蘋果泥) + 薯仔/紅蘿蔔 + 白飯 200g', '無糖豆漿 1盒 + 梳打餅 1小包', '滑蛋蝦仁 (大蝦 150g + 2蛋) + 白飯 200g + 燙小白菜', '【訓練日】茅屋芝士 (Cottage Cheese) 100g + 藍莓 (適合睡前)', '週末可先煮好白飯與藜麥分裝冷凍；雞腿肉先用無糖醬油醃製。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 9, 2, '星期二', '高蛋白鬆餅 (燕麥粉 + 乳清蛋白1勺 + 雞蛋) + 無糖糖漿 + 奇異果', '蒜香牛油煎白身魚 (龍脷/鯛魚 200g) + 烤番薯 250g + 翠玉瓜', '米餅 (Rice Cakes) 3塊 + 抹低脂忌廉芝士 + 火雞胸肉片 3片', '泰式打拋豬肉 (瘦豬絞肉 150g + 九層塔 + 番茄) + 糙米飯 200g', '【訓練日】乳清蛋白粉 1 勺 + 飯糰 1 個 (紫菜包飯)', '按照當日食譜烹調，注意少油少糖。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 10, 2, '星期三', '蕎麥麵 (冷) + 水煮蛋2隻 + 海帶芽 + 芝麻醬少許', '韓式辣醬炒豬梅肉(去肥) 150g + 紫菜包飯 (飯200g) + 菠菜', '蘋果 1個 + 杏仁/核桃 20g', '蒜香辣椒大蜆炒意粉 (大蜆/青口 200g + 全麥意粉 100g) + 雜菜沙律', '【休息日】黑豆漿 1 杯 (不需高碳水)', '按照當日食譜烹調，注意少油少糖。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 11, 2, '星期四', '牛肉碎粥 (白飯熬製 + 瘦牛肉碎 100g) + 蔥花 + 薑絲', '照燒去皮雞腿肉 150g + 白飯 200g + 西蘭花 1.5碗 (備餐神器)', '水煮蛋 2隻 + 地瓜 100g', '雞胸肉法吉塔 (Fajitas: 雞胸 150g + 甜椒 + 洋蔥 + 墨西哥捲餅皮 2片)', '【訓練日】乳清蛋白粉 1 勺 + 穀物片小半碗', '按照當日食譜烹調，注意少油少糖。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 12, 2, '星期五', '花生醬香蕉三文治 (全麥包2片 + 花生醬1.5湯匙 + 香蕉1隻) + 脫脂奶一條', '黑椒洋蔥炒瘦牛柳絲 150g + 烏冬 1.5個 + 菜心 1.5碗', '全麥方包 1片 + 吞拿魚(水浸) 半罐 + 低脂沙律醬', '清蒸石斑/鱸魚 200g (薑蔥豉油少許) + 白飯 200g + 炒生菜', '【訓練日】乳清蛋白粉 1 勺 + 香蕉 1 隻', '薯仔和南瓜切塊蒸熟，放保鮮盒；大蝦可買急凍剝殼蝦仁退冰。');
