INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 14, 2, '星期日', '全麥多士2片 + 炒蛋 (2全蛋+2蛋白) + 蘑菇番茄 + 1/4個牛油果', '番茄肉醬意粉 (瘦豬肉碎 150g + 全麥意粉 100g乾重 + 洋蔥番茄熬汁)', '高蛋白能量棒 (Protein Bar) 1條', '香煎牛板腱 (Flat Iron) 150g + 烤南瓜 250g + 蒜蓉炒芥蘭', '【休息日】無糖高鈣奶 250ml (不需高碳水)', '豬鞍/豬梅肉用蒜茸和少許生抽醃製；燕麥可前一晚做好放雪櫃。');
