INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 28, 4, '星期日', '高蛋白鬆餅 (燕麥粉 + 乳清蛋白1勺 + 雞蛋) + 無糖糖漿 + 奇異果', '照燒去皮雞腿肉 150g + 白飯 200g + 西蘭花 1.5碗 (備餐神器)', '香蕉 1隻 + 希臘乳酪 100g', '滑蛋蝦仁 (大蝦 150g + 2蛋) + 白飯 200g + 燙小白菜', '【休息日】黑豆漿 1 杯 (不需高碳水)', '豬鞍/豬梅肉用蒜茸和少許生抽醃製；燕麥可前一晚做好放雪櫃。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 29, 5, '星期一', '牛肉碎粥 (白飯熬製 + 瘦牛肉碎 100g) + 蔥花 + 薑絲', '番茄肉醬意粉 (瘦豬肉碎 150g + 全麥意粉 100g乾重 + 洋蔥番茄熬汁)', '蘋果 1個 + 杏仁/核桃 20g', '黑椒蘑菇烤豬鞍片 (150g) + 薯蓉 (薯仔200g+低脂奶打成) + 蘆筍', '【訓練日】乳清蛋白粉 1 勺 + 飯糰 1 個 (紫菜包飯)', '週末可先煮好白飯與藜麥分裝冷凍；雞腿肉先用無糖醬油醃製。');
INSERT INTO meal_days (meal_plan_id, day_number, week_number, day_of_week, breakfast, lunch, afternoon_snack, dinner, supplements, tips) VALUES ((SELECT id FROM meal_plans WHERE is_template = TRUE AND name = '60 天 Lean Bulk 餐單'), 30, 5, '星期二', '花生醬香蕉三文治 (全麥包2片 + 花生醬1.5湯匙 + 香蕉1隻) + 脫脂奶一條', '日式咖哩雞胸肉 150g (無糖咖哩粉+少量蘋果泥) + 薯仔/紅蘿蔔 + 白飯 200g', '水煮蛋 2隻 + 地瓜 100g', '香煎牛板腱 (Flat Iron) 150g + 烤南瓜 250g + 蒜蓉炒芥蘭', '【訓練日】黑豆漿 1 杯 + 奇異果 1 個 (休息日替換)', '按照當日食譜烹調，注意少油少糖。');
